Bash(php -r "
\\$value = '9.501E+11';
if \(preg_match\('/^\(\\d+\)\\.\(\\d+\)E\\+\(\\d+\)$/', \\$value, \\$matches\)\) {
    echo \\"Pattern matched!\\" . PHP_EOL;
    echo \\"Base: \\$matches[1]\\$matches[2]\\" . PHP_EOL;
    echo \\"Exponent: \\$matches[3]\\" . PHP_EOL;
    \\$base = \\$matches[1].\\$matches[2];
    \\$exponent = \(int\)\\$matches[3];
    echo \\"Padded: \\" . str_pad\(\\$base, \\$exponent + 1, '0'\) . PHP_EOL;
} else {
    echo \\"Pattern did not match\\" . PHP_EOL;
}
")

